                    // Compare distances (index 0 of the element array)
                    if (left <= lastIndex && this.heap[left][0] < this.heap[smallest][0]) {
                        smallest = left;
                    }
                    if (right <= lastIndex && this.heap[right][0] < this.heap[smallest][0]) {
                        smallest = right;
                    }

                    if (smallest !== index) {
                        [this.heap[index], this.heap[smallest]] = [this.heap[smallest], this.heap[index]];
                        index = smallest;
                    } else {
                        break;
                    }
                }
            }
        }

        const pq = new MinPriorityQueue();
        pq.enqueue([0, startNode]);

        while (!pq.isEmpty()) {
            const [d, u] = pq.dequeue();

            if (d > dist[u]) continue;

            // Neighbors of u:
            const neighbors = [];

            // 1. Closest move
            const closestU = closest[u];
            if (closestU !== -1) {
                neighbors.push({ v: closestU, weight: 1 });
            }

            // 2. Sequential moves (Direct jumps to adjacent indices)
            // To adjacent node v=u+1
            if (u + 1 < n) {
                const v = u + 1;
                const weight = Math.abs(nums[u] - nums[v]);
                neighbors.push({ v: v, weight: weight });
            }
            // To adjacent node v=u-1
            if (u - 1 >= 0) {
                const v = u - 1;
                const weight = Math.abs(nums[u] - nums[v]);
                neighbors.push({ v: v, weight: weight });
            }

            // Note: We only need to consider these O(1) edges per node, as established by the analysis above.

            for (const { v, weight } of neighbors) {
                const newDist = dist[u] + weight;
                if (newDist < dist[v]) {
                    dist[v] = newDist;
                    pq.enqueue([newDist, v]);
                }
            }
        }
        return dist;
    };

    // Step 3: Process Queries
    const results = [];
    for (const [l, r] of queries) {
        // Since we need shortest path from l to r, we run Dijkstra from l.
        const distances = dijkstra(l);
        results.push(distances[r]);
    }

    return results;
}
